### src/layout.js
     1	import { $, rand, TAU } from './util.js';
     2	import { GW, GH } from './path.js';
     3	
     4	/* ============ LAYOUT ============ */
     5	/* Canvas, sizing/DPR, grid→pixel helpers, and the pre-rendered/cached visual
     6	   layers (nebula bg, vignette, glow sprites, starfield, warping mesh grid).
     7	   Scalars are `export let` — ES module live bindings, so importers always see
     8	   the values assigned by the latest resize(). Only this module writes them. */
     9	export const cv=$('cv'),ctx=cv.getContext('2d');
    10	export let W=0,H=0,CS=40,OX=0,OY=0,DPR=1;
    11	export function resize(){DPR=Math.min(window.devicePixelRatio||1,3);
    12	  W=window.innerWidth;H=window.innerHeight;
    13	  cv.width=W*DPR;cv.height=H*DPR;cv.style.width=W+'px';cv.style.height=H+'px';
    14	  const topPad=86,botPad=118;
    15	  CS=Math.min(W/GW,(H-topPad-botPad)/GH);
    16	  OX=(W-CS*GW)/2;OY=topPad+((H-topPad-botPad)-CS*GH)/2;
    17	  starsInit();buildBg();meshInit();}
    18	export const cx=x=>OX+x*CS, cy=y=>OY+y*CS;
    19	window.addEventListener('resize',resize);
    20	
    21	export let stars=[];
    22	function starsInit(){stars=[];for(let i=0;i<110;i++){const l=i%3;
    23	  stars.push({x:Math.random()*W,y:Math.random()*H,l,
    24	    r:l===2?rand(.9,1.9):l===1?rand(.5,1.2):rand(.3,.8),
    25	    spd:(l+1)*2.4,p:Math.random()*TAU,
    26	    col:Math.random()<.14?'#7ef0ff':Math.random()<.1?'#ffb0e0':'#9fc6e8'});}}
    27	
    28	/* nebula background + vignette, pre-rendered once per resize */
    29	export let bgCanvas=null,vigCanvas=null;
    30	function buildBg(){
    31	  bgCanvas=document.createElement('canvas');bgCanvas.width=W;bgCanvas.height=H;
    32	  const c2=bgCanvas.getContext('2d');
    33	  c2.fillStyle='#04060c';c2.fillRect(0,0,W,H);
    34	  const blob=(x,y,r,col)=>{const g=c2.createRadialGradient(x,y,0,x,y,r);
    35	    g.addColorStop(0,col);g.addColorStop(1,'rgba(0,0,0,0)');
    36	    c2.fillStyle=g;c2.fillRect(0,0,W,H);};
    37	  blob(W*.12,H*.22,W*.75,'rgba(18,60,125,.17)');
    38	  blob(W*.92,H*.48,W*.65,'rgba(120,18,90,.13)');
    39	  blob(W*.42,H*.88,W*.75,'rgba(58,22,125,.15)');
    40	  blob(W*.78,H*.07,W*.5,'rgba(0,95,115,.13)');
    41	  vigCanvas=document.createElement('canvas');vigCanvas.width=W;vigCanvas.height=H;
    42	  const v=vigCanvas.getContext('2d');
    43	  const vg=v.createRadialGradient(W/2,H/2,Math.min(W,H)*.42,W/2,H/2,Math.hypot(W,H)*.62);
    44	  vg.addColorStop(0,'rgba(2,3,8,0)');vg.addColorStop(1,'rgba(2,3,8,.62)');
    45	  v.fillStyle=vg;v.fillRect(0,0,W,H);
    46	}
    47	
    48	/* cached radial glow sprites per color */
    49	const glowCache={};
    50	export function glow(color){let g=glowCache[color];if(g)return g;
    51	  g=document.createElement('canvas');g.width=g.height=64;
    52	  const c2=g.getContext('2d');
    53	  const gr=c2.createRadialGradient(32,32,0,32,32,32);
    54	  gr.addColorStop(0,'rgba(255,255,255,.95)');gr.addColorStop(.28,color);gr.addColorStop(1,'rgba(0,0,0,0)');
    55	  c2.fillStyle=gr;c2.fillRect(0,0,64,64);
    56	  glowCache[color]=g;return g;}
    57	export function blitGlow(color,x,y,r,alpha){ctx.globalAlpha=alpha;
    58	  ctx.drawImage(glow(color),x-r,y-r,r*2,r*2);ctx.globalAlpha=1;}
    59	
    60	/* warping grid mesh — explosions ripple through it */
    61	export let mesh=[];
    62	function meshInit(){mesh=[];
    63	  for(let r=0;r<=GH;r++)for(let c=0;c<=GW;c++){
    64	    const x=cx(c),y=cy(r);
    65	    mesh.push({x,y,rx:x,ry:y,vx:0,vy:0});}}
    66	export function meshImpulse(gx,gy,pow){if(!mesh.length)return;
    67	  const ex=cx(gx),ey=cy(gy),R=CS*3.4;
    68	  for(const p of mesh){const dx=p.rx-ex,dy=p.ry-ey,d=Math.hypot(dx,dy);
    69	    if(d<R&&d>1){const f=pow*(1-d/R);p.vx+=dx/d*f;p.vy+=dy/d*f;}}}
    70	export function meshUpdate(dt){const damp=Math.exp(-7*dt);
    71	  for(const p of mesh){
    72	    p.vx+=(p.rx-p.x)*70*dt;p.vy+=(p.ry-p.y)*70*dt;
    73	    p.vx*=damp;p.vy*=damp;
    74	    p.x+=p.vx*dt;p.y+=p.vy*dt;}}
