     9	import { sfx } from './audio.js';
    10	import { updateHUD, updateWaveBtn } from './hud.js';
    11	import { startWave, spawnEnemy } from './waves.js';
    12	import { nearestEnemies, hurt, leak, fireTower } from './combat.js';
    13	import { render } from './render.js';
    14	import { gameOver, toMenu } from './ui.js';
    15	
    16	/* ============ UPDATE ============ */
    17	function update(dt){
    18	  S.G.time+=dt;
    19	  // spawns
    20	  if(S.G.waveActive){S.G.waveT+=dt;
    21	    while(S.G.spawnQ.length&&S.G.spawnQ[0].t<=S.G.waveT){spawnEnemy(S.G.spawnQ.shift().type);}}
    22	  // enemies
    23	  for(const e of S.G.enemies){
    24	    if(e.dead)continue;
    25	    const sm=S.G.time<e.slowUntil?e.slowMult:1;
    26	    e.t+=e.spd*sm*dt;
    27	    const[tpx,tpy]=posAt(e.t);
    28	    e.tr.push(tpx,tpy);if(e.tr.length>12)e.tr.splice(0,2);
    29	    if(e.shieldMax&&e.shield<e.shieldMax&&S.G.time-e.lastHit>2)e.shield=Math.min(e.shieldMax,e.shield+e.shieldMax*.12*dt);
    30	    if(e.t>=totalLen){e.dead=true;leak(e);}}
    31	  S.G.enemies=S.G.enemies.filter(e=>!e.dead);
    32	  if(S.G.health<=0){gameOver();return;} // leak() only drains health; flow owns the death check
    33	  // towers
    34	  for(const tw of S.G.towers.values())fireTower(tw,dt);
    35	  // projectiles
    36	  for(const p of S.G.projs){
    37	    if(p.k==='bolt'){
    38	      if(p.tgt&&!p.tgt.dead){const[tx,ty]=posAt(p.tgt.t);
    39	        const a=Math.atan2(ty-p.y,tx-p.x);p.vx=Math.cos(a)*p.spd;p.vy=Math.sin(a)*p.spd;}
    40	      p.x+=p.vx*dt;p.y+=p.vy*dt;
    41	      if(p.tgt&&!p.tgt.dead){const[tx,ty]=posAt(p.tgt.t);
    42	        if(Math.hypot(tx-p.x,ty-p.y)<p.tgt.r+.18){hurt(p.tgt,p.dmg,p.color);burst(p.x,p.y,p.color,3);p.gone=true;}}
    43	      if(p.x<-1||p.x>GW+1||p.y<-1||p.y>GH+1)p.gone=true;
    44	    }else if(p.k==='shell'){
    45	      p.p+=dt/p.fly;
    46	      if(p.p>=1){p.gone=true;sfx('nova');
    47	        S.G.fx.push({k:'ring',x:p.tx,y:p.ty,r0:.1,r1:p.aoe,ttl:.3,max:.3,color:p.color});
    48	        S.G.fx.push({k:'flash',x:p.tx,y:p.ty,r:p.aoe*1.1,ttl:.28,max:.28,color:p.color});
    49	        meshImpulse(p.tx,p.ty,140);
    50	        burst(p.tx,p.ty,p.color,14,1.4);S.G.shake=Math.max(S.G.shake,3);
    51	        for(const c of nearestEnemies(p.tx,p.ty,p.aoe))hurt(c.e,p.dmg*(1-c.d/p.aoe*.4),p.color);}
    52	      else{const k=p.p;p.x=p.sx+(p.tx-p.sx)*k;p.y=p.sy+(p.ty-p.sy)*k-Math.sin(k*Math.PI)*1.1;}
    53	    }}
    54	  S.G.projs=S.G.projs.filter(p=>!p.gone);
    55	  // fx / particles / text
    56	  for(const f of S.G.fx){f.ttl-=dt;
    57	    if(f.k==='shard'){f.x+=f.vx*dt;f.y+=f.vy*dt;f.vx*=.985;f.vy*=.985;f.rot+=f.vr*dt;}}
    58	  S.G.fx=S.G.fx.filter(f=>f.ttl>0);
    59	  meshUpdate(dt);
    60	  for(const p of S.G.parts){p.x+=p.vx*dt;p.y+=p.vy*dt;p.vx*=.96;p.vy*=.96;p.life-=dt;}
    61	  S.G.parts=S.G.parts.filter(p=>p.life>0);
    62	  for(const t of S.G.texts){t.y-=dt*.8;t.life-=dt*.9;}
    63	  S.G.texts=S.G.texts.filter(t=>t.life>0);
    64	  S.G.shake=Math.max(0,S.G.shake-dt*30);
    65	  S.G.flash=Math.max(0,S.G.flash-dt*1.8);
    66	  // wave end
    67	  if(S.G.waveActive&&!S.G.spawnQ.length&&!S.G.enemies.length){
    68	    S.G.waveActive=false;
    69	    const bonus=Math.round((25+S.G.wave*6)*salvMul()*tuning.economy);
    70	    S.G.credits+=bonus;S.G.score+=200+S.G.wave*50;
    71	    sfx('cash');toast('WAVE CLEAR  +'+bonus+' ◈');
    72	    S.G.countdown=10;S.dirtyHud=true;}
    73	  // countdown (HUD refreshed only when the displayed second changes)
    74	  if(!S.G.waveActive&&S.G.countdown>0){const cs=Math.ceil(S.G.countdown);S.G.countdown-=dt;
    75	    if(Math.ceil(S.G.countdown)!==cs)S.dirtyHud=true;
    76	    if(S.G.countdown<=0)startWave();}
    77	}
