    80	let last=performance.now();
    81	function loop(now){
    82	  requestAnimationFrame(loop);
    83	  let dt=Math.min(.034,(now-last)/1000);last=now;
    84	  if(S.state==='play'&&!S.paused)update(dt*S.speed*GAME_SPEED*tuning.gameSpeed);
    85	  if(S.dirtyHud){S.dirtyHud=false;updateHUD();updateWaveBtn();}
    86	  render();
    87	}
    88	document.addEventListener('visibilitychange',()=>{if(document.hidden&&S.state==='play')S.paused||($('pauseBtn').click());});
    89	document.addEventListener('gesturestart',e=>e.preventDefault());
    90	resize();
