### src/path.js
     1	import { clamp } from './util.js';
     2	
     3	/* ============ GRID & PATH ============ */
     4	export const GW=9,GH=14;
     5	export const WP=[[-0.7,1.5],[7.5,1.5],[7.5,4.5],[1.5,4.5],[1.5,7.5],[7.5,7.5],[7.5,10.5],[1.5,10.5],[1.5,12.5],[8.5,12.5]];
     6	export const PATH_INT=[[0,1],[7,1],[7,4],[1,4],[1,7],[7,7],[7,10],[1,10],[1,12],[8,12]];
     7	export const pathCells=new Set();
     8	for(let i=0;i<PATH_INT.length-1;i++){let[x0,y0]=PATH_INT[i],[x1,y1]=PATH_INT[i+1];
     9	  const dx=Math.sign(x1-x0),dy=Math.sign(y1-y0);let x=x0,y=y0;pathCells.add(x+','+y);
    10	  while(x!==x1||y!==y1){x+=dx;y+=dy;pathCells.add(x+','+y);}}
    11	export const BASE=[8,12];
    12	export const segLen=[];export let totalLen=0;
    13	for(let i=0;i<WP.length-1;i++){const l=Math.hypot(WP[i+1][0]-WP[i][0],WP[i+1][1]-WP[i][1]);segLen.push(l);totalLen+=l;}
    14	export function posAt(t){t=clamp(t,0,totalLen);let acc=0;
    15	  for(let i=0;i<segLen.length;i++){if(t<=acc+segLen[i]){const k=(t-acc)/segLen[i];
    16	    return[WP[i][0]+(WP[i+1][0]-WP[i][0])*k,WP[i][1]+(WP[i+1][1]-WP[i][1])*k];}acc+=segLen[i];}
    17	  return[WP[WP.length-1][0],WP[WP.length-1][1]];}
    18	export function dirAt(t){t=clamp(t,0,totalLen-.001);let acc=0;
    19	  for(let i=0;i<segLen.length;i++){if(t<=acc+segLen[i]){const dx=WP[i+1][0]-WP[i][0],dy=WP[i+1][1]-WP[i][1];
    20	    const l=segLen[i];return[dx/l,dy/l];}acc+=segLen[i];}return[1,0];}
### src/render.js
     1	import { clamp, rand, TAU } from './util.js';
     2	import { S } from './state.js';
     3	import { GW, GH, WP, pathCells, BASE, totalLen, posAt, dirAt } from './path.js';
     4	import { TOWERS } from './config.js';
     5	import { ctx, W, H, CS, DPR, cx, cy, stars, bgCanvas, vigCanvas, glow, blitGlow, mesh } from './layout.js';
     6	
     7	/* ============ RENDER ============ */
     8	export function render(){
     9	  ctx.setTransform(DPR,0,0,DPR,0,0);
    10	  if(bgCanvas)ctx.drawImage(bgCanvas,0,0,W,H);
    11	  else{ctx.fillStyle='#04060c';ctx.fillRect(0,0,W,H);}
    12	  const t=S.G?S.G.time:performance.now()/1000;
    13	  // parallax starfield (3 drifting layers)
    14	  for(const s of stars){
    15	    ctx.fillStyle=s.col;
    16	    ctx.globalAlpha=(.16+.2*Math.sin(t*1.7+s.p))*(s.l+1)*.5;
    17	    ctx.fillRect((s.x+t*s.spd)%W,s.y,s.r,s.r);}
    18	  ctx.globalAlpha=1;
    19	  if(!S.G){if(vigCanvas)ctx.drawImage(vigCanvas,0,0,W,H);return;}
    20	  // shake
    21	  ctx.save();
    22	  if(S.G.shake>0)ctx.translate(rand(-S.G.shake,S.G.shake)*.6,rand(-S.G.shake,S.G.shake)*.6);
    23	  // warping energy grid
    24	  const P=(c,r)=>mesh[r*(GW+1)+c];
    25	  ctx.strokeStyle='rgba(60,115,170,.17)';ctx.lineWidth=1;
    26	  ctx.beginPath();
    27	  for(let r=0;r<=GH;r++){ctx.moveTo(P(0,r).x,P(0,r).y);
    28	    for(let c=1;c<=GW;c++)ctx.lineTo(P(c,r).x,P(c,r).y);}
    29	  for(let c=0;c<=GW;c++){ctx.moveTo(P(c,0).x,P(c,0).y);
    30	    for(let r=1;r<=GH;r++)ctx.lineTo(P(c,r).x,P(c,r).y);}
    31	  ctx.stroke();
    32	  // displaced segments glow cyan
    33	  ctx.save();ctx.globalCompositeOperation='lighter';
    34	  ctx.strokeStyle='rgba(70,190,255,.3)';ctx.lineWidth=1.2;
    35	  const disp=p=>Math.abs(p.x-p.rx)+Math.abs(p.y-p.ry);
    36	  ctx.beginPath();
    37	  for(let r=0;r<=GH;r++)for(let c=0;c<GW;c++){const a=P(c,r),b=P(c+1,r);
    38	    if(disp(a)+disp(b)>2.5){ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);}}
    39	  for(let c=0;c<=GW;c++)for(let r=0;r<GH;r++){const a=P(c,r),b=P(c,r+1);
    40	    if(disp(a)+disp(b)>2.5){ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);}}
    41	  ctx.stroke();ctx.restore();
    42	  // buildable cell dots
    43	  ctx.fillStyle='rgba(80,140,200,.13)';
    44	  for(let c=0;c<GW;c++)for(let r=0;r<GH;r++){
    45	    if(pathCells.has(c+','+r))continue;
    46	    ctx.fillRect(cx(c+.5)-1,cy(r+.5)-1,2,2);}
    47	  // path: layered energy river
    48	  const lane=()=>{ctx.beginPath();ctx.moveTo(cx(WP[0][0]),cy(WP[0][1]));
    49	    for(let i=1;i<WP.length;i++)ctx.lineTo(cx(WP[i][0]),cy(WP[i][1]));};
