     9	/* waveSpawns is pure (given config + tuning) — the boss sfx/banner side effect
    10	   lives in startWave, so admin jump-to-wave and tests can build schedules freely. */
    11	export function waveSpawns(n){
    12	  const s=[];let t=0;
    13	  const add=(type,count,gap)=>{count=Math.max(1,Math.round(count*SPAWN_COUNT_SCALE*tuning.enemyCount));for(let i=0;i<count;i++){s.push({t,type});t+=gap;}t+=1;};
    14	  if(n%8===0){
    15	    add('boss',Math.max(1,Math.floor(n/24)+1),3.5);
    16	    add('drone',6+n,0.5);
    17	    if(n>=16)add('shield',Math.floor(n/8),1);
    18	  }else{
    19	    add('drone',Math.min(26,7+n),0.55);
    20	    if(n>=3)add('dart',3+Math.floor(n*.8),0.32);
    21	    if(n>=5)add('swarm',Math.min(30,6+n),0.17);
    22	    if(n>=7)add('tank',1+Math.floor(n/3),1.2);
    23	    if(n>=10)add('shield',1+Math.floor(n/4),0.95);
    24	    if(n>=14)add('dart',Math.floor(n*.6),0.25);
    25	  }
    26	  return s;
    27	}
    28	export const hpMul=n=>1+n*.16+n*n*.013;
