    31	  S.G.spawnQ=waveSpawns(S.G.wave);
    32	  if(S.G.wave%8===0){sfx('boss');banner('⚠ BOSS INBOUND ⚠','#ff2255');buzz(80);}
    33	  else{sfx('wave');banner('WAVE '+S.G.wave,'#22d8ff');}
    34	  S.dirtyHud=true;
    35	}
    36	export function spawnEnemy(type){
    37	  const d=ENEMIES[type],m=hpMul(S.G.wave)*tuning.enemyHp;
    38	  const hp=d.hp*m*(type==='boss'?(1+S.G.wave*.06):1);
    39	  S.G.enemies.push({type,t:0,hp,maxHp:hp,spd:d.spd*(1+Math.min(.5,S.G.wave*.008))*tuning.enemySpeed,
    40	    r:d.r,color:d.color,slowUntil:0,slowMult:1,tr:[],
    41	    shield:d.shield?d.shield*m:0,shieldMax:d.shield?d.shield*m:0,lastHit:-9,
    42	    wob:Math.random()*TAU,dead:false});
    43	}
