    47	
    48	/* cached radial glow sprites per color */
    49	const glowCache={};
    50	export function glow(color){let g=glowCache[color];if(g)return g;
    51	  g=document.createElement('canvas');g.width=g.height=64;
    52	  const c2=g.getContext('2d');
    53	  const gr=c2.createRadialGradient(32,32,0,32,32,32);
    54	  gr.addColorStop(0,'rgba(255,255,255,.95)');gr.addColorStop(.28,color);gr.addColorStop(1,'rgba(0,0,0,0)');
