    16	    return[WP[i][0]+(WP[i+1][0]-WP[i][0])*k,WP[i][1]+(WP[i+1][1]-WP[i][1])*k];}acc+=segLen[i];}
    17	  return[WP[WP.length-1][0],WP[WP.length-1][1]];}
    18	export function dirAt(t){t=clamp(t,0,totalLen-.001);let acc=0;
    19	  for(let i=0;i<segLen.length;i++){if(t<=acc+segLen[i]){const dx=WP[i+1][0]-WP[i][0],dy=WP[i+1][1]-WP[i][1];
    20	    const l=segLen[i];return[dx/l,dy/l];}acc+=segLen[i];}return[1,0];}
