     1	/* ============ DEV TUNING ============ */
     2	/* Global balance multipliers, mutated live by the admin overlay (admin.js) and
     3	   read at the game's balance chokepoints (main.js). Persisted to localStorage so
     4	   tuned values survive a reload while balancing. Dev-only — never wired in prod. */
     5	
     6	// Neutral by default: the real balance is baked into config.js. These are pure
     7	// dev-overlay deltas on top of the shipped numbers — 1× means "no change".
     8	export const TUNING_DEFAULTS = {
     9	  enemyHp: 1,        // enemy HP (and shield) multiplier
    10	  enemySpeed: 1,     // enemy move-speed multiplier
    11	  enemyCount: 1,     // per-wave spawn-count multiplier
    12	  towerDmg: 1,       // all tower damage multiplier
    13	  towerRate: 1,      // tower fire-rate multiplier
    14	  towerRange: 1,     // tower range multiplier
    15	  economy: 1,        // credit income + starting credits multiplier
    16	  gameSpeed: 1,      // extra game-speed multiplier (on top of the 1×/2× button)
    17	  coreInvincible: false, // leaks deal no core damage when true (debug only)
    18	};
    19	
    20	// Bumped to .v2 when balance was folded into config.js — invalidates older saved
    21	// tuning so it can't double-apply on top of the now-baked numbers.
    22	const KEY = 'neonGridDefense.tuning.v2';
    23	
    24	export const tuning = { ...TUNING_DEFAULTS };
    25	try {
    26	  const s = localStorage.getItem(KEY);
    27	  if (s) Object.assign(tuning, JSON.parse(s));
    28	} catch (e) {}
    29	
    30	export function saveTuning() {
    31	  try { localStorage.setItem(KEY, JSON.stringify(tuning)); } catch (e) {}
    32	}
    33	
    34	export function resetTuning() {
    35	  Object.assign(tuning, TUNING_DEFAULTS);
    36	  saveTuning();
    37	}
