    36	    c2.fillStyle=g;c2.fillRect(0,0,W,H);};
    37	  blob(W*.12,H*.22,W*.75,'rgba(18,60,125,.17)');
    38	  blob(W*.92,H*.48,W*.65,'rgba(120,18,90,.13)');
    39	  blob(W*.42,H*.88,W*.75,'rgba(58,22,125,.15)');
