     8	for(let i=0;i<PATH_INT.length-1;i++){let[x0,y0]=PATH_INT[i],[x1,y1]=PATH_INT[i+1];
     9	  const dx=Math.sign(x1-x0),dy=Math.sign(y1-y0);let x=x0,y=y0;pathCells.add(x+','+y);
    10	  while(x!==x1||y!==y1){x+=dx;y+=dy;pathCells.add(x+','+y);}}
