  1	import { clamp } from './util.js';
  2	import { S, dmgMul, salvMul } from './state.js';
  3	import { posAt, totalLen } from './path.js';
  4	import { sfx, buzz } from './audio.js';
  5	import { burst, shatter, addText, banner } from './fx.js';
  6	import { meshImpulse } from './layout.js';
  7	import { TOWERS, ENEMIES } from './config.js';
  8	import { tuning } from './tuning.js';
  9	
 10	/* ============ COMBAT ============ */
 11	/* leak() only drains health — the game-over check lives in update() (main.js),
 12	   keeping combat free of any flow/UI dependency. */
 13	export function nearestEnemies(x,y,range){
 14	  const out=[];for(const e of S.G.enemies){if(e.dead)continue;
 15	    const[ex,ey]=posAt(e.t);const d=Math.hypot(ex-x,ey-y);
 16	    if(d<=range)out.push({e,d,ex,ey});}
 17	  return out;}
 18	export function pickTarget(list,prio){if(!list.length)return null;
 19	  let best=list[0];
 20	  for(const c of list){
 21	    if(prio==='strong'){if(c.e.hp+c.e.shield>best.e.hp+best.e.shield)best=c;}
 22	    else{if(c.e.t>best.e.t)best=c;}}
 23	  return best;}
 24	export function hurt(e,dmg,color){
 25	  e.lastHit=S.G.time;
 26	  if(e.shield>0){e.shield-=dmg;if(e.shield<0){e.hp+=e.shield;e.shield=0;}}
 27	  else e.hp-=dmg;
 28	  if(e.hp<=0&&!e.dead){e.dead=true;kill(e,color);}
 29	}
 30	export function kill(e,color){
 31	  const d=ENEMIES[e.type];
 32	  const credits=Math.round(d.bounty*salvMul()*tuning.economy);
 33	  S.G.credits+=credits;S.G.kills++;
 34	  S.G.streak++;S.G.mult=Math.min(8,1+S.G.streak*.1);
 35	  S.G.score+=Math.round(d.score*S.G.mult);
 36	  const[x,y]=posAt(e.t);
 37	  burst(x,y,e.color,e.type==='boss'?60:e.type==='tank'?22:10,e.type==='boss'?3:1);
 38	  shatter(x,y,e.color,e.type==='boss'?18:e.type==='tank'?10:6,e.r*2.4);
 39	  meshImpulse(x,y,e.type==='boss'?340:e.type==='tank'?170:75);
 40	  S.G.fx.push({k:'flash',x,y,r:e.type==='boss'?2.6:e.r*2.6,ttl:.3,max:.3,color:e.color});
 41	  addText(x,y,'+'+credits,'#ffe93c');
 42	  if(e.type==='boss'){S.G.shake=14;S.G.flash=.5;sfx('boom');buzz(60);banner('BOSS DOWN  +'+credits,'#54ff7c');}
 43	  else if(e.type==='tank'){S.G.shake=Math.max(S.G.shake,5);sfx('boom');}
 44	  else sfx('kill');
 45	  S.dirtyHud=true;
 46	}
 47	export function leak(e){
 48	  const d=ENEMIES[e.type];
 49	  if(!tuning.coreInvincible)S.G.health-=d.dmg||1;
 50	  S.G.streak=0;S.G.mult=1;S.G.shake=10;S.G.flash=.6;
 51	  sfx('leak');buzz(100);
 52	  const[x,y]=posAt(totalLen-.1);burst(x,y,'#ff2255',24,1.6);
 53	  meshImpulse(x,y,260);
 54	  S.G.fx.push({k:'flash',x,y,r:1.6,ttl:.4,max:.4,color:'#ff2255'});
 55	  S.dirtyHud=true;
 56	}
 57	export function fireTower(tw,dt){
 58	  const def=TOWERS[tw.type],st=def.tiers[tw.tier];
 59	  const range=st.range*tuning.towerRange,rate=st.rate*tuning.towerRate;
 60	  tw.cd-=dt;if(tw.cd>0)return;
 61	  const x=tw.c+.5,y=tw.r+.5;
 62	  if(tw.type==='cryo'){
 63	    const list=nearestEnemies(x,y,range);if(!list.length)return;
 64	    tw.cd=1/rate;sfx('cryo');
 65	    S.G.fx.push({k:'ring',x,y,r0:.2,r1:range,ttl:.45,max:.45,color:def.color});
 66	    for(const c of list){c.e.slowUntil=S.G.time+st.slowT;c.e.slowMult=1-st.slow;hurt(c.e,st.dmg*dmgMul(),def.color);}
 67	    return;}
 68	  const list=nearestEnemies(x,y,range);
 69	  const tgt=pickTarget(list,tw.prio);if(!tgt)return;
 70	  tw.cd=1/rate;tw.aim=Math.atan2(tgt.ey-y,tgt.ex-x);
 71	  if(tw.type==='pulse'){
 72	    sfx('shoot');
 73	    S.G.projs.push({k:'bolt',x,y,tgt:tgt.e,spd:10,dmg:st.dmg*dmgMul(),color:def.color,
 74	      vx:Math.cos(tw.aim)*10,vy:Math.sin(tw.aim)*10});
 75	  }else if(tw.type==='nova'){
 76	    sfx('shoot');
 77	    const fly=tgt.d/6;
 78	    const lead=clamp(tgt.e.t+tgt.e.spd*tgt.e.slowMult*fly,0,totalLen);
 79	    const[px,py]=posAt(lead);
 80	    S.G.projs.push({k:'shell',x,y,sx:x,sy:y,tx:px,ty:py,p:0,fly:Math.max(.18,fly),
 81	      dmg:st.dmg*dmgMul(),aoe:st.aoe,color:def.color});
 82	  }else if(tw.type==='lance'){
 83	    sfx('lance');
 84	    const dx=Math.cos(tw.aim),dy=Math.sin(tw.aim);
 85	    const ex=x+dx*range,ey=y+dy*range;
 86	    S.G.fx.push({k:'beam',x1:x,y1:y,x2:ex,y2:ey,ttl:.18,max:.18,color:def.color});
 87	    for(const c of nearestEnemies(x,y,range+1)){
 88	      const px=c.ex-x,py=c.ey-y;const proj=px*dx+py*dy;
 89	      if(proj<0||proj>range)continue;
 90	      const perp=Math.abs(px*dy-py*dx);
 91	      if(perp<.38+c.e.r)hurt(c.e,st.dmg*dmgMul(),def.color);}
 92	    S.G.shake=Math.max(S.G.shake,2);
 93	  }else if(tw.type==='arc'){
 94	    sfx('arc');
 95	    const hitOrder=[];const visited=new Set();
 96	    let cur=tgt;visited.add(cur.e);hitOrder.push([x,y],[cur.ex,cur.ey]);
 97	    hurt(cur.e,st.dmg*dmgMul(),def.color);
 98	    for(let i=1;i<st.chains;i++){
 99	      let next=null,nd=1.9;
100	      for(const c of nearestEnemies(cur.ex,cur.ey,1.9)){
101	        if(visited.has(c.e))continue;
102	        if(c.d<nd){nd=c.d;next=c;}}
103	      if(!next)break;
104	      visited.add(next.e);hitOrder.push([next.ex,next.ey]);
105	      hurt(next.e,st.dmg*dmgMul()*Math.pow(.85,i),def.color);
106	      cur=next;}
107	    S.G.fx.push({k:'arc',pts:hitOrder,ttl:.16,max:.16,color:def.color});
108	  }
109	}

