 65	    S.G.fx.push({k:'ring',x,y,r0:.2,r1:range,ttl:.45,max:.45,color:def.color});
 66	    for(const c of list){c.e.slowUntil=S.G.time+st.slowT;c.e.slowMult=1-st.slow;hurt(c.e,st.dmg*dmgMul(),def.color);}
 67	    return;}
 68	  const list=nearestEnemies(x,y,range);
 69	  const tgt=pickTarget(list,tw.prio);if(!tgt)return;
 70	  tw.cd=1/rate;tw.aim=Math.atan2(tgt.ey-y,tgt.ex-x);
 71	  if(tw.type==='pulse'){
 72	    sfx('shoot');
 73	    S.G.projs.push({k:'bolt',x,y,tgt:tgt.e,spd:10,dmg:st.dmg*dmgMul(),color:def.color,
 74	      vx:Math.cos(tw.aim)*10,vy:Math.sin(tw.aim)*10});
 75	  }else if(tw.type==='nova'){
 76	    sfx('shoot');
 77	    const fly=tgt.d/6;
 78	    const lead=clamp(tgt.e.t+tgt.e.spd*tgt.e.slowMult*fly,0,totalLen);
 79	    const[px,py]=posAt(lead);
 80	    S.G.projs.push({k:'shell',x,y,sx:x,sy:y,tx:px,ty:py,p:0,fly:Math.max(.18,fly),
 81	      dmg:st.dmg*dmgMul(),aoe:st.aoe,color:def.color});
 82	  }else if(tw.type==='lance'){
 83	    sfx('lance');
 84	    const dx=Math.cos(tw.aim),dy=Math.sin(tw.aim);
 85	    const ex=x+dx*range,ey=y+dy*range;
 86	    S.G.fx.push({k:'beam',x1:x,y1:y,x2:ex,y2:ey,ttl:.18,max:.18,color:def.color});
 87	    for(const c of nearestEnemies(x,y,range+1)){
 88	      const px=c.ex-x,py=c.ey-y;const proj=px*dx+py*dy;
 89	      if(proj<0||proj>range)continue;
 90	      const perp=Math.abs(px*dy-py*dx);
 91	      if(perp<.38+c.e.r)hurt(c.e,st.dmg*dmgMul(),def.color);}
 92	    S.G.shake=Math.max(S.G.shake,2);
 93	  }else if(tw.type==='arc'){
 94	    sfx('arc');
 95	    const hitOrder=[];const visited=new Set();
 96	    let cur=tgt;visited.add(cur.e);hitOrder.push([x,y],[cur.ex,cur.ey]);
 97	    hurt(cur.e,st.dmg*dmgMul(),def.color);
 98	    for(let i=1;i<st.chains;i++){
 99	      let next=null,nd=1.9;
100	      for(const c of nearestEnemies(cur.ex,cur.ey,1.9)){
101	        if(visited.has(c.e))continue;
102	        if(c.d<nd){nd=c.d;next=c;}}
103	      if(!next)break;
104	      visited.add(next.e);hitOrder.push([next.ex,next.ey]);
105	      hurt(next.e,st.dmg*dmgMul()*Math.pow(.85,i),def.color);
106	      cur=next;}
107	    S.G.fx.push({k:'arc',pts:hitOrder,ttl:.16,max:.16,color:def.color});
108	  }
109	}

