 1	import { meta, saveMeta } from './save.js';
 2	
 3	/* ============ AUDIO ============ */
 4	let AC=null,masterGain=null,lastSfx={};
 5	export function audioInit(){if(AC)return;try{AC=new (window.AudioContext||window.webkitAudioContext)();
 6	  masterGain=AC.createGain();masterGain.gain.value=meta.mute?0:0.5;masterGain.connect(AC.destination);}catch(e){}}
 7	export function setMute(m){meta.mute=m;saveMeta();if(masterGain)masterGain.gain.value=m?0:0.5;}
 8	function tone(f0,f1,dur,type,vol,when){if(!AC)return;const t=AC.currentTime+(when||0);
 9	  const o=AC.createOscillator(),g=AC.createGain();o.type=type;o.frequency.setValueAtTime(f0,t);
10	  o.frequency.exponentialRampToValueAtTime(Math.max(f1,1),t+dur);
11	  g.gain.setValueAtTime(vol,t);g.gain.exponentialRampToValueAtTime(.0001,t+dur);
12	  o.connect(g);g.connect(masterGain);o.start(t);o.stop(t+dur+.02);}
13	function noise(dur,vol,fc){if(!AC)return;const n=AC.sampleRate*dur|0,b=AC.createBuffer(1,n,AC.sampleRate),d=b.getChannelData(0);
14	  for(let i=0;i<n;i++)d[i]=(Math.random()*2-1)*(1-i/n);
15	  const s=AC.createBufferSource();s.buffer=b;const f=AC.createBiquadFilter();f.type='lowpass';f.frequency.value=fc;
16	  const g=AC.createGain();g.gain.value=vol;s.connect(f);f.connect(g);g.connect(masterGain);s.start();}
17	export function sfx(name){if(!AC||meta.mute)return;const now=performance.now();
18	  if(lastSfx[name]&&now-lastSfx[name]<50)return;lastSfx[name]=now;
19	  switch(name){
20	    case 'shoot':tone(880,220,.07,'square',.05);break;
21	    case 'nova':tone(160,40,.2,'sawtooth',.1);noise(.18,.12,900);break;
22	    case 'arc':tone(1400,300,.1,'sawtooth',.06);break;
23	    case 'lance':tone(2200,180,.16,'sawtooth',.08);break;
24	    case 'cryo':tone(520,900,.14,'sine',.07);break;
25	    case 'kill':tone(660,1320,.09,'square',.06);break;
26	    case 'boom':noise(.3,.2,600);tone(120,30,.3,'sine',.18);break;
27	    case 'build':tone(330,660,.12,'square',.09);tone(495,990,.12,'square',.06,.05);break;
28	    case 'upgrade':tone(440,880,.1,'square',.08);tone(660,1320,.1,'square',.08,.07);tone(880,1760,.12,'square',.08,.14);break;
29	    case 'sell':tone(700,200,.18,'square',.08);break;
30	    case 'leak':tone(180,60,.4,'sawtooth',.2);noise(.25,.15,400);break;
31	    case 'wave':tone(220,880,.35,'sawtooth',.08);break;
32	    case 'boss':tone(110,110,.5,'sawtooth',.16);tone(116,116,.5,'sawtooth',.16);break;
33	    case 'click':tone(700,500,.05,'square',.05);break;
34	    case 'deny':tone(200,150,.12,'square',.08);break;
35	    case 'over':[523,392,311,233,165].forEach((f,i)=>tone(f,f*.5,.3,'sawtooth',.1,i*.16));break;
36	    case 'cash':tone(987,1976,.08,'square',.05);break;
37	  }}
38	export function buzz(ms){if(navigator.vibrate)try{navigator.vibrate(ms);}catch(e){}}

