  1	/* ============ DEV ADMIN OVERLAY ============ */
  2	/* Live balance-tuning panel. Dev-only: main.js imports this dynamically behind
  3	   import.meta.env.DEV, so it is tree-shaken out of production builds. Toggle with
  4	   the backtick (`) key. Sliders write the shared `tuning` object (read live by the
  5	   game); debug actions call back into the game through the `api` passed to initAdmin. */
  6	
  7	import { tuning, saveTuning, resetTuning } from './tuning.js';
  8	
  9	// label, key, min, max, step
 10	const SLIDERS = [
 11	  ['Enemy HP',      'enemyHp',     0.25, 8,   0.05],
 12	  ['Enemy speed',   'enemySpeed',  0.25, 4,   0.05],
 13	  ['Enemy count',   'enemyCount',  0.25, 6,   0.05],
 14	  ['Tower damage',  'towerDmg',    0.1,  8,   0.05],
 15	  ['Tower rate',    'towerRate',   0.25, 5,   0.05],
 16	  ['Tower range',   'towerRange',  0.5,  3,   0.05],
 17	  ['Economy',       'economy',     0.25, 8,   0.05],
 18	  ['Game speed',    'gameSpeed',   0.25, 4,   0.05],
 19	];
 20	
 21	// Copy text to clipboard. Tries the async Clipboard API, then falls back to a
 22	// hidden textarea + execCommand (works when the Clipboard API is blocked, e.g.
 23	// NotAllowedError). Returns whether the copy succeeded.
 24	async function copyText(text) {
 25	  if (navigator.clipboard?.writeText) {
 26	    try { await navigator.clipboard.writeText(text); return true; } catch (e) {}
 27	  }
 28	  try {
 29	    const ta = document.createElement('textarea');
 30	    ta.value = text;
 31	    ta.style.cssText = 'position:fixed;top:0;left:0;opacity:0';
 32	    document.body.appendChild(ta);
 33	    ta.focus(); ta.select();
 34	    const ok = document.execCommand('copy');
 35	    document.body.removeChild(ta);
 36	    return ok;
 37	  } catch (e) { return false; }
 38	}
 39	
 40	export function initAdmin(api) {
 41	  const root = document.createElement('div');
 42	  root.id = 'admin';
 43	  root.hidden = true;
 44	
 45	  const refreshers = [];
 46	  const h = (html) => { const d = document.createElement('div'); d.innerHTML = html; return d; };
 47	
 48	  root.appendChild(h(`<div class="admin-title">⚙ BALANCE <span class="admin-hint">\` to toggle</span></div>`));
 49	
 50	  // --- sliders ---
 51	  for (const [label, key, min, max, step] of SLIDERS) {
 52	    const row = document.createElement('div');
 53	    row.className = 'admin-row';
 54	    const out = document.createElement('span');
 55	    out.className = 'admin-val';
 56	    const input = document.createElement('input');
 57	    input.type = 'range';
 58	    input.min = min; input.max = max; input.step = step;
 59	    const sync = () => { input.value = tuning[key]; out.textContent = (+tuning[key]).toFixed(2) + '×'; };
 60	    input.addEventListener('input', () => {
 61	      tuning[key] = parseFloat(input.value);
 62	      out.textContent = tuning[key].toFixed(2) + '×';
 63	      saveTuning();
 64	    });
 65	    row.appendChild(h(`<label>${label}</label>`).firstChild);
 66	    row.appendChild(input);
 67	    row.appendChild(out);
 68	    root.appendChild(row);
 69	    refreshers.push(sync);
 70	    sync();
 71	  }
 72	
 73	  // --- invincible core toggle ---
 74	  const invRow = document.createElement('div');
 75	  invRow.className = 'admin-row admin-toggle';
 76	  const invBtn = document.createElement('button');
 77	  const syncInv = () => {
 78	    invBtn.textContent = 'INVINCIBLE CORE: ' + (tuning.coreInvincible ? 'ON' : 'OFF');
 79	    invBtn.classList.toggle('on', tuning.coreInvincible);
 80	  };
 81	  invBtn.addEventListener('click', () => { tuning.coreInvincible = !tuning.coreInvincible; saveTuning(); syncInv(); });
 82	  invRow.appendChild(invBtn);
 83	  root.appendChild(invRow);
 84	  refreshers.push(syncInv);
 85	  syncInv();
 86	
 87	  // --- debug actions ---
 88	  const actions = document.createElement('div');
 89	  actions.className = 'admin-actions';
 90	
 91	  const mkBtn = (text, fn) => { const b = document.createElement('button'); b.textContent = text; b.addEventListener('click', fn); return b; };
 92	
 93	  // jump to wave: number input + go
 94	  const waveWrap = document.createElement('div');
 95	  waveWrap.className = 'admin-row';
 96	  const waveInput = document.createElement('input');
 97	  waveInput.type = 'number'; waveInput.min = 1; waveInput.value = 8; waveInput.className = 'admin-num';
 98	  waveWrap.appendChild(h(`<label>Jump to wave</label>`).firstChild);
 99	  waveWrap.appendChild(waveInput);
100	  waveWrap.appendChild(mkBtn('GO', () => api.jumpToWave(Math.max(1, parseInt(waveInput.value, 10) || 1))));
101	  root.appendChild(waveWrap);
102	
103	  actions.appendChild(mkBtn('+1000 ◈', () => api.addCredits(1000)));
104	  actions.appendChild(mkBtn('KILL ALL', () => api.killAll()));
105	  actions.appendChild(mkBtn('RESET', () => { resetTuning(); refreshers.forEach((f) => f()); }));
106	  actions.appendChild(mkBtn('COPY', async (e) => {
107	    const json = JSON.stringify(tuning, null, 2);
108	    const ok = await copyText(json);
109	    e.target.textContent = ok ? 'COPIED' : 'COPY FAILED';
110	    setTimeout(() => (e.target.textContent = 'COPY'), 1200);
111	    if (!ok) window.prompt('Copy the tuning JSON manually:', json);
112	  }));
113	  root.appendChild(actions);
114	
115	  document.body.appendChild(root);
116	
117	  window.addEventListener('keydown', (ev) => {
118	    // backtick toggles; ignore when typing in the wave field
119	    if (ev.key === '`') { root.hidden = !root.hidden; if (!root.hidden) refreshers.forEach((f) => f()); }
120	  });
121	
122	  console.info('[admin] balance overlay ready — press ` to toggle');
123	}

